--
-- Table structure for table `reval_summary`
--

DROP TABLE IF EXISTS `reval_summary`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reval_summary` (
  `Summary_Id` bigint NOT NULL AUTO_INCREMENT,
  `Reval_Date` date NOT NULL COMMENT 'Revaluation date',
  `Total_Accounts` int NOT NULL DEFAULT '0' COMMENT 'Total number of accounts revalued',
  `GL_Accounts` int NOT NULL DEFAULT '0' COMMENT 'Number of GL accounts (Nostro) revalued',
  `Customer_Accounts` int NOT NULL DEFAULT '0' COMMENT 'Number of customer accounts revalued',
  `Total_Gain` decimal(20,2) NOT NULL DEFAULT '0.00' COMMENT 'Total unrealized gain',
  `Total_Loss` decimal(20,2) NOT NULL DEFAULT '0.00' COMMENT 'Total unrealized loss (positive)',
  `Net_Reval` decimal(20,2) NOT NULL DEFAULT '0.00' COMMENT 'Net revaluation (gain - loss)',
  `Start_Time` datetime NOT NULL COMMENT 'When revaluation started',
  `End_Time` datetime DEFAULT NULL COMMENT 'When revaluation completed',
  `Duration_Seconds` int DEFAULT NULL COMMENT 'Processing duration in seconds',
  `Status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'COMPLETED' COMMENT 'RUNNING, COMPLETED, FAILED, REVERSED',
  `Error_Message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Error message if failed',
  `Reversed_On` datetime DEFAULT NULL COMMENT 'When BOD reversal was performed',
  `Reversal_Duration_Seconds` int DEFAULT NULL COMMENT 'BOD reversal duration',
  `Executed_By` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'User/system who executed',
  `Created_On` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `Last_Updated` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`Summary_Id`),
  UNIQUE KEY `Reval_Date` (`Reval_Date`),
  KEY `idx_reval_summary_date` (`Reval_Date`),
  KEY `idx_reval_summary_status` (`Status`),
  CONSTRAINT `chk_reval_summary_status` CHECK ((`Status` in (_utf8mb4'RUNNING',_utf8mb4'COMPLETED',_utf8mb4'FAILED',_utf8mb4'REVERSED')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Daily summary of EOD revaluation process';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `reval_summary`
--

LOCK TABLES `reval_summary` WRITE;
/*!40000 ALTER TABLE `reval_summary` DISABLE KEYS */;
