-- Table structure for table `reval_tran`
--

DROP TABLE IF EXISTS `reval_tran`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reval_tran` (
  `Reval_Id` bigint NOT NULL AUTO_INCREMENT,
  `Reval_Date` date NOT NULL COMMENT 'Date of revaluation (EOD date)',
  `Acct_Num` varchar(20) NOT NULL COMMENT 'FCY account being revalued',
  `Ccy_Code` varchar(3) NOT NULL COMMENT 'Foreign currency code',
  `FCY_Balance` decimal(20,2) NOT NULL COMMENT 'FCY balance at EOD',
  `Mid_Rate` decimal(10,4) NOT NULL COMMENT 'Mid rate used for revaluation',
  `Booked_LCY` decimal(20,2) NOT NULL COMMENT 'Booked LCY equivalent (cumulative)',
  `MTM_LCY` decimal(20,2) NOT NULL COMMENT 'Mark-to-market LCY value',
  `Reval_Diff` decimal(20,2) NOT NULL COMMENT 'Revaluation difference (MTM - Booked)',
  `Reval_GL` varchar(20) DEFAULT NULL COMMENT 'Revaluation GL (NULL for baseline/skipped records)',
  `Tran_Id` varchar(30) DEFAULT NULL COMMENT 'Transaction ID in tran_table',
  `Reversal_Tran_Id` varchar(30) DEFAULT NULL COMMENT 'BOD reversal transaction ID',
  `Status` varchar(20) NOT NULL DEFAULT 'POSTED' COMMENT 'POSTED or REVERSED',
  `Created_On` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `Reversed_On` datetime DEFAULT NULL COMMENT 'BOD reversal timestamp',
  PRIMARY KEY (`Reval_Id`),
  KEY `idx_reval_date` (`Reval_Date`),
  KEY `idx_acct_num` (`Acct_Num`),
  KEY `idx_status` (`Status`),
  KEY `idx_tran_id` (`Tran_Id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Revaluation transactions for FCY accounts - EOD mark-to-market entries';
/*!40101 SET character_set_client = @saved_cs_client */;

