--
-- Table structure for table `settlement_gain_loss`
--

DROP TABLE IF EXISTS `settlement_gain_loss`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `settlement_gain_loss` (
  `Settlement_Id` bigint NOT NULL AUTO_INCREMENT,
  `Tran_Id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Base transaction ID (without -1, -2 suffix)',
  `Tran_Date` date NOT NULL COMMENT 'Transaction date',
  `Value_Date` date NOT NULL COMMENT 'Value date',
  `Account_No` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Customer account number',
  `Account_Name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Customer account name',
  `Currency` varchar(3) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Foreign currency code (USD, EUR, etc.)',
  `FCY_Amt` decimal(20,2) NOT NULL COMMENT 'Foreign currency amount sold',
  `Deal_Rate` decimal(10,4) NOT NULL COMMENT 'Deal rate (customer rate)',
  `WAE_Rate` decimal(10,4) NOT NULL COMMENT 'WAE rate (weighted average exchange rate)',
  `Settlement_Amt` decimal(20,2) NOT NULL COMMENT 'Settlement gain (+) or loss (-) amount in BDT',
  `Settlement_Type` varchar(4) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'GAIN or LOSS',
  `Settlement_GL` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'GL account used (140203001 for GAIN, 240203001 for LOSS)',
  `Position_GL` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Position GL account (920101001, 920102001, etc.)',
  `Entry5_Tran_Id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Transaction ID of entry 5',
  `Entry6_Tran_Id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Transaction ID of entry 6',
  `Posted_By` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'User who posted the transaction',
  `Posted_On` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Timestamp when posted',
  `Status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'POSTED' COMMENT 'POSTED, REVERSED, or CANCELLED',
  `Reversal_Id` bigint DEFAULT NULL COMMENT 'Reference to reversal settlement record if reversed',
  `Reversed_On` datetime DEFAULT NULL COMMENT 'Timestamp when reversed',
  `Narration` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Transaction narration',
  `Created_On` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `Last_Updated` datetime DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`Settlement_Id`),
  KEY `idx_settlement_tran_id` (`Tran_Id`),
  KEY `idx_settlement_account` (`Account_No`),
  KEY `idx_settlement_date` (`Tran_Date`),
  KEY `idx_settlement_currency` (`Currency`),
  KEY `idx_settlement_status` (`Status`),
  KEY `idx_settlement_type` (`Settlement_Type`),
  CONSTRAINT `chk_settlement_status` CHECK ((`Status` in (_utf8mb4'POSTED',_utf8mb4'REVERSED',_utf8mb4'CANCELLED'))),
  CONSTRAINT `chk_settlement_type` CHECK ((`Settlement_Type` in (_utf8mb4'GAIN',_utf8mb4'LOSS')))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Tracks settlement gain/loss calculations for MCT SELL transactions';
/*!40101 SET character_set_client = @saved_cs_client */;

