DROP TABLE IF EXISTS `tran_value_date_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tran_value_date_log` (
  `Log_Id` bigint NOT NULL AUTO_INCREMENT,
  `Tran_Id` varchar(20) NOT NULL,
  `Value_Date` date NOT NULL,
  `Days_Difference` int NOT NULL,
  `Delta_Interest_Amt` decimal(20,4) DEFAULT '0.0000',
  `Adjustment_Posted_Flag` varchar(1) DEFAULT 'N',
  `Created_Timestamp` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`Log_Id`),
  KEY `idx_tran_id` (`Tran_Id`),
  KEY `idx_value_date` (`Value_Date`),
  KEY `idx_posted_flag` (`Adjustment_Posted_Flag`),
  KEY `idx_value_date_flag` (`Value_Date`,`Adjustment_Posted_Flag`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
