--
-- Table structure for table `value_date_intt_accr`
--

DROP TABLE IF EXISTS `value_date_intt_accr`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `value_date_intt_accr` (
  `Accr_Tran_Id` varchar(20) NOT NULL,
  `Account_No` varchar(13) NOT NULL,
  `Accrual_Date` date NOT NULL,
  `Interest_Rate` decimal(10,4) NOT NULL,
  `Amount` decimal(20,2) NOT NULL,
  `Status` enum('Pending','Posted','Verified') NOT NULL DEFAULT 'Pending',
  `Tran_Date` date DEFAULT NULL,
  `Value_Date` date DEFAULT NULL,
  `Dr_Cr_Flag` enum('D','C') DEFAULT NULL,
  `Original_Dr_Cr_Flag` enum('D','C') DEFAULT NULL COMMENT 'Original transaction Dr/Cr flag from tran_table (for balance impact calculation)',
  `Tran_Status` enum('Entry','Posted','Verified','Future') DEFAULT NULL,
  `GL_Account_No` varchar(20) DEFAULT NULL,
  `Tran_Ccy` varchar(3) DEFAULT NULL,
  `FCY_Amt` decimal(20,2) DEFAULT NULL,
  `Exchange_Rate` decimal(10,4) DEFAULT NULL,
  `LCY_Amt` decimal(20,2) DEFAULT NULL,
  `Narration` varchar(100) DEFAULT NULL,
  `UDF1` varchar(50) DEFAULT NULL,
  `Tran_Id` varchar(20) DEFAULT NULL COMMENT 'Source transaction ID that triggered value date interest',
  `Day_Gap` int DEFAULT NULL COMMENT 'Number of days between Value_Date and Tran_Date',
  PRIMARY KEY (`Accr_Tran_Id`),
  KEY `idx_value_date_intt_accr_tran_date` (`Tran_Date`),
  KEY `idx_value_date_intt_accr_account_date` (`Account_No`,`Tran_Date`),
  KEY `idx_value_date_intt_accr_tran_id` (`Tran_Id`),
  KEY `idx_value_date_intt_accr_accrual_date` (`Accrual_Date`),
  CONSTRAINT `value_date_intt_accr_ibfk_1` FOREIGN KEY (`Account_No`) REFERENCES `cust_acct_master` (`Account_No`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

