DROP TABLE IF EXISTS `wae_master`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wae_master` (
  `WAE_Id` bigint NOT NULL AUTO_INCREMENT,
  `Ccy_Pair` varchar(10) NOT NULL COMMENT 'Currency pair (e.g., USD/BDT, EUR/BDT)',
  `WAE_Rate` decimal(10,4) NOT NULL DEFAULT '0.0000' COMMENT 'Weighted average exchange rate',
  `FCY_Balance` decimal(20,2) NOT NULL DEFAULT '0.00' COMMENT 'Net FCY balance (cumulative)',
  `LCY_Balance` decimal(20,2) NOT NULL DEFAULT '0.00' COMMENT 'Equivalent LCY balance (cumulative)',
  `Updated_On` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `Source_GL` varchar(20) DEFAULT NULL COMMENT 'Position GL account reference',
  PRIMARY KEY (`WAE_Id`),
  UNIQUE KEY `unique_ccy_pair` (`Ccy_Pair`),
  KEY `idx_ccy_pair` (`Ccy_Pair`),
  KEY `idx_wae_master_ccy_gl` (`Ccy_Pair`,`Source_GL`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Weighted Average Exchange rates for settlement gain/loss calculation';
